import React, { useState } from "react";

import {
  Cloud,
  Sprout,
  ShoppingBag,
  Building2,
  Map,
  FileBarChart,
  TrendingUp,
  TrendingDown,
  Phone,
  Send,
  ChevronRight,
  ArrowRight,
} from "lucide-react";

import "./Dashboard.css";

const marketPrices = [
  {
    icon: "🌾",
    name: "Rice",
    price: "₹2800 / Quintal",
    change: "+2.5%",
    up: true,
  },

  {
    icon: "🍅",
    name: "Tomato",
    price: "₹32 / Kg",
    change: "-1.2%",
    up: false,
  },

  {
    icon: "🧅",
    name: "Onion",
    price: "₹28 / Kg",
    change: "-0.8%",
    up: false,
  },

  {
    icon: "🌿",
    name: "Cotton",
    price: "₹7600 / Quintal",
    change: "+1.5%",
    up: true,
  },
];

const forecast = [
  {
    day: "Today",
    icon: "⛅",
    temp: "31°C",
    rain: "20%",
  },

  {
    day: "Tomorrow",
    icon: "🌧️",
    temp: "30°C",
    rain: "40%",
  },

  {
    day: "Monday",
    icon: "☀️",
    temp: "33°C",
    rain: "10%",
  },

  {
    day: "Tuesday",
    icon: "☀️",
    temp: "34°C",
    rain: "0%",
  },
];

const schemes = [
  {
    icon: "👨‍🌾",
    name: "PM Kisan",
    desc: "Direct income support",
  },

  {
    icon: "🛡️",
    name: "PM Fasal Bima",

    desc: "Crop insurance",
  },

  {
    icon: "💧",
    name: "PM Krishi Sinchai",

    desc: "Irrigation support",
  },

  {
    icon: "💳",
    name: "Kisan Credit Card",

    desc: "Easy farmer credit",
  },
];

const quickActions = [
  {
    icon: Cloud,
    label: "Weather",
  },

  {
    icon: Sprout,
    label: "Crop Advisor",
  },

  {
    icon: ShoppingBag,
    label: "Market Prices",
  },

  {
    icon: Building2,
    label: "Government Schemes",
  },

  {
    icon: FileBarChart,
    label: "Reports",
  },

  {
    icon: Map,
    label: "Maps",
  },
];

export default function Dashboard({ setActivePage }) {
  const [chatInput, setChatInput] = useState("");

  const [chatMessages, setChatMessages] = useState([]);

  function handleSend() {
    if (!chatInput.trim()) return;

    let reply = "";

    const q = chatInput.toLowerCase();

    if (q.includes("rice")) {
      reply = "Rice needs NPK fertilizer.";
    }

    else if (q.includes("cotton")) {
      reply = "Cotton grows well in warm weather.";
    }

    else if (q.includes("rain")) {
      reply = "Tomorrow rain chance is 40%.";
    }

    else if (q.includes("fertilizer")) {
      reply = "Organic fertilizer is recommended.";
    }

    else {
      reply = "Please ask another farming question.";
    }

    setChatMessages((p) => [
      ...p,

      {
        text: chatInput,
        user: true,
      },

      {
        text: reply,
        user: false,
      },
    ]);

    setChatInput("");
  }

  return (
    <div className="dashboard-layout">

